import java.security.*; // Import cryptographic methods from the Standard Provider Classes in Java SE Platform Library, such as MessageDigest and KeyPairGenerator for generating keys etc., it includes classes like SHA1Hasher (used below), KeysManager which is used to handle all types of key pairs including symmetric algorithm eccKeyPairs.
import java.util.*; //Import necessary utilities needed in this task – such as ArrayList, HashMap and others   .These include tools for handling different data structures etc..    For instance Collections class java_50654_CredentialValidator_A08 various functions related collection operations like add(), remove()...etc., Arrays package which has array-related methods (such sorting algorithms), BigInteger is used to handle big integers – in this case, passwords and keys.
import sun.security.util.*; //Import cryptographic utility classes from Java SE Platform Library such as SHA1Hasher for the purpose of creating a hash function...etc..     .Sun-provided class names are prefixed with 'sun' to avoid conflict on name clashes between different provider packages in Sun RPC (Java Remote Method Invocation)
import javax.crypto.*; // Import cryptographic classes from Java Cryptography Architecture and Security API – for implementing symmetric algorithms like AES, DES etc...etc..   .This includes KeyGenerators to generate keys among other stuffs such as SecretKeyFactory which can create a secret key in the desired algorithm based on inputs
import javax.crypto.spec.*; // Import cryptographic specification classes from Java Cryptography Architecture and Security API – for creating cipher specifications...etc..    .This includes things like AES keys, DES etc., IvParameterSpec (initialization vector) which is used to encrypt/decrypt the data
